import React from "react";
import { useNavigate } from "react-router-dom";
import { Bus } from "../types";

type Props = {
  bus: Bus;
};

const BusCard: React.FC<Props> = ({ bus }) => {
  const navigate = useNavigate();
  const departureDate = new Date(bus.departureTime);
  const arrivalDate = new Date(bus.arrivalTime);
  const availableSeats = bus.seats.filter((seat) => seat.isAvailable).length;

  const durationMs = Math.max(arrivalDate.getTime() - departureDate.getTime(), 0);
  const durationHours = Math.floor(durationMs / (1000 * 60 * 60));
  const durationMinutes = Math.floor((durationMs % (1000 * 60 * 60)) / (1000 * 60));
  const ratingLabel = bus.rating >= 4.3 ? "Very Good" : bus.rating >= 4.0 ? "Good" : "Decent";

  return (
    <article className="rounded-2xl bg-white p-5 shadow-travel ring-1 ring-slate-200 transition hover:-translate-y-0.5">
      <div className="flex flex-wrap items-start justify-between gap-4">
        <div>
          <h3 className="text-lg font-bold text-slate-900">{bus.operatorName}</h3>
          <p className="mt-1 text-sm text-slate-600">
            {bus.departureCity} {" -> "} {bus.arrivalCity}
          </p>
          <p className="mt-2 text-sm text-slate-500">
            {departureDate.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })} {" -> "}{" "}
            {arrivalDate.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
          </p>
          <p className="mt-1 text-sm text-slate-500">
            Duration: {durationHours}h {durationMinutes}m
          </p>
          <p className="mt-2 text-sm font-semibold text-rose-600">Only {availableSeats} seats left</p>
        </div>

        <div className="text-right">
          <p className="inline-flex items-center rounded-full bg-amber-100 px-3 py-1 text-xs font-semibold text-amber-800">
            {bus.rating.toFixed(1)} {ratingLabel}
          </p>
          <p className="text-sm text-slate-500">{bus.isAC ? "AC" : "Non AC"}</p>
          <p className="text-sm text-slate-500">{bus.seatType}</p>
          <p className="mt-2 text-xl font-bold text-blue-700">INR {bus.price}</p>
        </div>
      </div>

      <div className="mt-4 flex flex-wrap gap-2">
        {bus.amenities.slice(0, 4).map((amenity) => (
          <span key={amenity} className="rounded-full bg-slate-100 px-3 py-1 text-xs font-medium text-slate-700">
            {amenity}
          </span>
        ))}
      </div>

      <div className="mt-5 flex items-center justify-between gap-3">
        <div className="text-xs text-slate-500">
          Boarding: {bus.boardingPoints[0]} | Dropping: {bus.droppingPoints[0]}
        </div>
        <button
          type="button"
          onClick={() => navigate(`/seats/${bus.id}`)}
          className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-blue-700"
        >
          View Seats
        </button>
      </div>
    </article>
  );
};

export default BusCard;
